import React from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Sidebar from './components/Sidebar';

// Importing your existing pages
import Dashboard from './pages/Dashboard';
import Explore from './pages/Explore';
import BarterChat from './pages/BarterChat';
import Notifications from './pages/Notifications';
import Profile from './pages/Profile';
import Settings from './pages/Settings';
import CreateListing from './pages/CreateListing';
import Login from './pages/Login';
import Register from './pages/Register';

// Layout wrapper to handle Sidebar visibility
function AppLayout({ children }) {
  const location = useLocation();
  // Hide sidebar on Login and Register pages
  const hideSidebar = location.pathname === '/' || location.pathname === '/register';

  return (
    <div className="flex bg-slate-50 min-h-screen">
      {!hideSidebar && <Sidebar />} 
      <main className="flex-1 overflow-y-auto">
        {children}
      </main>
    </div>
  );
}

export default function App() {
  return (
    <Router>
      <AppLayout>
        <Routes>
          {/* Auth Routes */}
          <Route path="/" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* App Routes */}
          <Route path="/dashboard" element={<Dashboard />} />
          <Route path="/explore" element={<Explore />} />
          <Route path="/messages" element={<BarterChat />} />
          <Route path="/notifications" element={<Notifications />} />
          <Route path="/profile" element={<Profile />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="/create" element={<CreateListing />} />
        </Routes>
      </AppLayout>
    </Router>
  );
}
